import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'API_KEY_MISSING',
      details: 'Vercel ড্যাশবোর্ডে "API_KEY" সেট করা নেই।' 
    });
  }

  try {
    const { contents, systemInstruction, tools, model, responseMimeType, responseSchema } = req.body;
    const ai = new GoogleGenAI({ apiKey });

    // Always prioritize Google Search for real-time accuracy
    const response = await ai.models.generateContent({
      model: model || 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী। গুগল সার্চ ব্যবহার করে সব সময় ইন্টারনেটে থাকা সর্বশেষ (Last 1-2 hours) তথ্য দিন।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.2, // Lower temperature for more factual responses
        responseMimeType,
        responseSchema,
      },
    });

    const textOutput = response.text || "দুঃখিত, বর্তমানে কোনো লাইভ আপডেট পাওয়া যায়নি।";

    return res.status(200).json({
      text: textOutput,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
      mode: 'live_cloud_v3_search'
    });

  } catch (error) {
    console.error("Vercel AI Bridge Error:", error.message);
    return res.status(500).json({ 
      error: 'AI_GATEWAY_ERROR',
      details: "সার্ভার রেসপন্স দিচ্ছে না।",
      raw: error.message
    });
  }
}

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Loader2, 
  TrainFront,
  X,
  Sparkles,
  Info,
  Navigation,
  RefreshCcw,
  DollarSign,
  AlertCircle,
  Clock,
  Search,
  ExternalLink,
  ChevronRight,
  Globe,
  Facebook
} from 'lucide-react';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';
import { RAJBARI_DATA } from '../constants.tsx';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[] }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: []
  });

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else {
        const items = await db.getCategory(category);
        setData(items);
      }
    } catch (e: any) {
      const items = await db.getCategory(category);
      setData(items);
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  const runMarketAI = async () => {
    try {
      const response = await db.callAI({
        contents: [{ parts: [{ text: "রাজবাড়ী জেলার স্থানীয় বাজারের নিত্যপণ্যের দামের একটি বর্তমান JSON তালিকা দিন। ফিল্ডগুলো হবে: name, unit, priceRange।" }] }],
        systemInstruction: "আপনি রাজবাড়ী জেলা বাজার মনিটরিং অফিসার। শুধু JSON Array দিন।",
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
      else throw new Error("JSON parsing failed");
    } catch (err) {
      setData((RAJBARI_DATA as any).market_price);
    }
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'অনলাইনে লাইভ আপডেট খোঁজা হচ্ছে...', isAI: true, sources: [] });

    try {
      const now = new Date().toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit', hour12: true });
      const prompt = `
      লাইভ ট্র্যাকিং অ্যালার্ট!
      ট্রেন: "${train.name}" (ID: ${train.id})
      বর্তমান সময়: ${now}

      নির্দেশনা:
      ১. ইন্টারনেটে (বিশেষ করে Facebook Groups যেমন: Rajbari Rail Club, Bangladesh Railway Updates এবং Local News) এই ট্রেনের গত ১ ঘণ্টার মধ্যে কোনো অবস্থান সংক্রান্ত তথ্য আছে কি না তা গুগল সার্চের মাধ্যমে খুঁজে বের করুন।
      ২. যদি কোনো লাইভ রিপোর্ট পান, তবে ট্রেনটি বর্তমানে ঠিক কোথায় আছে (স্টেশনের নাম) তা উল্লেখ করুন।
      ৩. যদি কোনো লাইভ রিপোর্ট না পাওয়া যায়, তবে "বর্তমানে অনলাইনে কোনো লাইভ আপডেট পাওয়া যায়নি" লিখে অফিশিয়াল শিডিউল অনুযায়ী এর অবস্থান কী হওয়া উচিত তা স্পষ্টভাবে বলুন।
      ৪. অবশ্যই আপনার উত্তরের শেষে "[STATION: স্টেশনের নাম]" ফরম্যাটে বর্তমান অবস্থানটি উল্লেখ করুন।

      উত্তরের ভাষা: শুদ্ধ বাংলা।
      `;

      const response = await db.callAI({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        systemInstruction: "আপনি রাজবাড়ী রেলওয়ে কন্ট্রোল রুমের লাইভ এআই অ্যাসিস্ট্যান্ট। গুগল সার্চ ব্যবহার করে আপনি রিয়েল-টাইম ডাটা প্রোভাইড করেন।",
        tools: [{ googleSearch: {} }]
      });

      const text = response.text || "দুঃখিত, কোনো সাম্প্রতিক তথ্য পাওয়া যায়নি।";
      const stationMatch = text.match(/\[STATION:\s*(.*?)\]/i);

      if (stationMatch && stationMatch[1] && !stationMatch[1].includes("অজানা")) {
        const found = stationMatch[1].trim();
        setCurrentStation(found);
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 1, 
        reason: text.replace(/\[STATION:.*?\]/i, '').trim(), 
        isAI: true, 
        sources: response.groundingMetadata?.groundingChunks || [] 
      });
    } catch (e: any) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: "নেটওয়ার্ক সমস্যার কারণে লাইভ আপডেট নেওয়া সম্ভব হয়নি। অনুগ্রহ করে পুনরায় চেষ্টা করুন।", 
        isAI: false, 
        sources: [] 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const renderItem = (item: any) => {
    if (category === 'market_price') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm hover:border-emerald-200 transition-all">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600 shadow-inner"><DollarSign className="w-7 h-7" /></div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-lg leading-tight">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p></div>
        </div>
        <div className="text-right"><div className="text-lg font-black text-slate-800 dark:text-white mb-1">{item.priceRange}</div></div>
      </div>
    );

    if (category === 'trains') return (
      <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 hover:border-indigo-400 transition-all group overflow-hidden relative">
        <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-500/5 rounded-full blur-3xl -mr-12 -mt-12 group-hover:bg-indigo-500/10"></div>
        <div className="flex items-start justify-between relative z-10">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:scale-110 transition-transform"><TrainFront className="w-6 h-6" /></div>
            <div>
              <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
            </div>
          </div>
          <div className="text-right flex flex-col items-end">
             <div className="bg-emerald-50 dark:bg-emerald-950/30 text-emerald-600 text-[9px] font-black px-2 py-0.5 rounded-full mb-1 border border-emerald-100 dark:border-emerald-900/50">LIVE TRACKING</div>
             <p className="text-sm font-black text-slate-800 dark:text-white flex items-center gap-2">
              <Clock className="w-3.5 h-3.5 text-indigo-500" />
              {item.departure}
            </p>
          </div>
        </div>
      </div>
    );

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm hover:shadow-md transition-shadow">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl shadow-inner">{item.icon || <Info className="w-6 h-6 text-indigo-500" />}</div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-sm leading-tight">{item.name || item.title || item.org}</h4><p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.mobile || item.time || item.deadline}</p></div>
        </div>
        {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 rounded-2xl active:scale-90 transition-all"><Phone className="w-5 h-5" /></a>}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-40 max-w-lg mx-auto overflow-x-hidden">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-slate-800 dark:text-white uppercase leading-none mb-1">
            {category === 'trains' ? 'লাইভ ট্রেন ট্র্যাকিং' : category === 'market_price' ? 'বাজারদর (AI)' : 'বিস্তারিত তালিকা'}
          </h3>
          <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em]">Global AI Access</p>
        </div>
        <button onClick={fetchData} className="bg-white dark:bg-slate-900 p-3.5 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800 text-indigo-600 active:rotate-180 transition-all duration-500">
           <RefreshCcw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-6">
          <div className="relative">
            <Loader2 className="w-16 h-16 animate-spin text-indigo-600 opacity-20" />
            <div className="absolute inset-0 flex items-center justify-center">
              <Search className="w-6 h-6 text-indigo-600 animate-pulse" />
            </div>
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">ডাটাবেস চেক করা হচ্ছে...</p>
        </div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? data.map(renderItem) : <div className="text-center py-20 text-slate-400 font-bold">কোনো তথ্য পাওয়া যায়নি।</div>}
        </div>
      )}

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex items-end md:items-center justify-center p-4">
          <div className="bg-slate-50 dark:bg-slate-900 w-full max-w-lg rounded-[3rem] overflow-hidden shadow-3xl relative animate-slide-up flex flex-col max-h-[90vh]">
            <button onClick={() => { setSelectedTrain(null); setCurrentStation(null); }} className="absolute top-6 right-6 p-2 bg-white dark:bg-slate-800 rounded-full text-slate-400 z-50 shadow-md hover:text-rose-500 transition-all"><X className="w-5 h-5" /></button>

            <div className="p-8 pb-32 overflow-y-auto no-scrollbar">
               <div className="flex items-center gap-4 mb-6">
                 <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-indigo-200 dark:shadow-none">
                    <TrainFront className="w-7 h-7" />
                 </div>
                 <div>
                    <h3 className="text-xl font-black text-slate-800 dark:text-white leading-tight">{selectedTrain.name}</h3>
                    <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest">{selectedTrain.route}</p>
                 </div>
               </div>

               {/* AI Report Card - With Search Grounding */}
               <div className="bg-white dark:bg-slate-800/50 rounded-[2rem] p-6 border border-slate-100 dark:border-slate-800 shadow-sm relative overflow-hidden mb-6">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-2">
                      <div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></div>
                      <span className="text-[11px] font-bold text-slate-500 dark:text-slate-400">লাইভ এআই রিপোর্ট (গুগল সার্চ)</span>
                    </div>
                    {aiInference.sources && aiInference.sources.length > 0 && (
                      <span className="text-[9px] bg-indigo-50 dark:bg-indigo-950 text-indigo-600 px-2 py-0.5 rounded-full font-black border border-indigo-100">VERIFIED SOURCE</span>
                    )}
                  </div>

                  <div className="text-sm font-medium text-slate-700 dark:text-slate-200 leading-relaxed mb-4">
                    {aiInference.reason}
                  </div>

                  {aiInference.sources && aiInference.sources.length > 0 && (
                    <div className="mt-4 pt-4 border-t border-slate-100 dark:border-slate-700">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-1.5">
                        <Globe className="w-3 h-3" /> তথ্যের উৎসসমূহ:
                      </p>
                      <div className="flex flex-wrap gap-2">
                        {aiInference.sources.map((chunk, idx) => chunk.web && (
                          <a 
                            key={idx} 
                            href={chunk.web.uri} 
                            target="_blank" 
                            className="bg-slate-50 dark:bg-slate-800 p-2 rounded-xl text-[10px] font-bold text-indigo-600 border border-slate-100 dark:border-slate-700 hover:bg-indigo-50 transition-colors flex items-center gap-1.5"
                          >
                            <ExternalLink className="w-3 h-3" /> {chunk.web.title || `Source ${idx+1}`}
                          </a>
                        ))}
                      </div>
                    </div>
                  )}

                  {isInferring && (
                    <div className="mt-4 flex items-center gap-2 text-indigo-500 font-black text-[10px] animate-pulse bg-indigo-50 dark:bg-indigo-950/30 p-3 rounded-2xl">
                       <Loader2 className="w-3 h-3 animate-spin" /> লেটেস্ট আপডেট খোঁজা হচ্ছে... (এটি ১ মিনিট পর্যন্ত সময় নিতে পারে)
                    </div>
                  )}
               </div>

               {/* Route Section */}
               <div className="space-y-4">
                 <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                    <MapPin className="w-3 h-3" /> বিস্তারিত রুট ম্যাপ
                 </h4>
                 <div className="relative pl-8 space-y-6 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[1.5px] before:bg-slate-200 dark:before:bg-slate-700">
                    {selectedTrain.detailedRoute.split(',').map((st, idx) => {
                      const stationName = st.trim();
                      const isCurrent = currentStation && stationName.includes(currentStation);
                      return (
                        <div key={idx} className="relative flex items-center gap-4">
                          <div className={`absolute -left-[22px] w-3 h-3 rounded-full border-2 bg-white dark:bg-slate-900 transition-all duration-700 ${isCurrent ? 'border-emerald-500 bg-emerald-500 scale-150 shadow-[0_0_10px_rgba(16,185,129,0.5)]' : 'border-slate-300 dark:border-slate-600'}`}></div>
                          <span className={`text-xs font-bold transition-colors ${isCurrent ? 'text-emerald-600 dark:text-emerald-400 scale-110 origin-left' : 'text-slate-500 dark:text-slate-400'}`}>{stationName}</span>
                          {isCurrent && <span className="bg-emerald-100 text-emerald-700 text-[8px] font-black px-2 py-0.5 rounded-full animate-bounce">LIVE</span>}
                        </div>
                      );
                    })}
                 </div>
               </div>
            </div>

            {/* Bottom Status Button */}
            <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-slate-50 dark:from-slate-900 via-slate-50/90 dark:via-slate-900/90 to-transparent">
               <button 
                 disabled={isInferring}
                 onClick={() => runTrainAIInference(selectedTrain)}
                 className={`w-full py-5 rounded-[1.8rem] flex items-center justify-center gap-3 text-white font-black shadow-2xl transition-all active:scale-95 ${currentStation && !isInferring ? 'bg-emerald-500 shadow-emerald-200 dark:shadow-none' : 'bg-indigo-600'}`}
               >
                 {isInferring ? (
                    <Loader2 className="w-5 h-5 animate-spin" />
                 ) : (
                    <Navigation className="w-5 h-5 fill-white/20" />
                 )}
                 {isInferring ? 'লোডিং...' : currentStation ? `ট্রেনটি এখন ${currentStation} স্টেশনে` : 'লাইভ আপডেট চেক করুন'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import { GoogleGenAI } from "@google/genai";

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    return res.status(500).json({ 
      error: 'API_KEY_MISSING',
      details: 'Vercel ড্যাশবোর্ড থেকে API_KEY পাওয়া যায়নি।' 
    });
  }

  try {
    const { contents, systemInstruction, tools, model } = req.body;
    const ai = new GoogleGenAI({ apiKey });

    const response = await ai.models.generateContent({
      model: model || 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল রেলওয়ে অ্যাসিস্ট্যান্ট। আপনার কাজ হলো গুগল সার্চ ব্যবহার করে ট্রেনের বর্তমান অবস্থান খুঁজে বের করা। যদি সঠিক অবস্থান না পাওয়া যায়, তবে শিডিউল অনুযায়ী সম্ভাব্য অবস্থান বলুন।",
        tools: tools || [{ googleSearch: {} }],
        temperature: 0.1, // তথ্যের নির্ভুলতা বাড়াতে টেম্পারেচার কমানো হয়েছে
      },
    });

    return res.status(200).json({
      text: response.text,
      groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
      mode: 'live_v4_deep_search'
    });

  } catch (error) {
    console.error("AI Bridge Error:", error.message);
    return res.status(500).json({ 
      error: 'AI_GATEWAY_ERROR',
      details: error.message
    });
  }
}

import React, { useState, useEffect } from 'react';
import { 
