  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setLastUpdateTime(new Date().toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit' }));

    setAiInference({ 
      delayMinutes: 0, 
      confidence: 0, 
      reason: 'ইন্টারনেটে ফেসবুক গ্রুপ এবং রেলওয়ে পোর্টাল থেকে তথ্য সংগ্রহ করা হচ্ছে...', 
      isAI: true, 
      sources: [],
      isLive: false 
