             <div className="bg-emerald-50 dark:bg-emerald-950/30 text-emerald-600 text-[9px] font-black px-2 py-0.5 rounded-full mb-1 border border-emerald-100">GPS TRACKING</div>
             <p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p>
          </div>
        </div>
      </div>
    );

    return (
