import { RAJBARI_DATA } from './constants.tsx';

// Declare puter for TypeScript environment
declare const puter: any;

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      // Find JSON block even if model wraps it in Markdown code blocks
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Puter.js AI Call implementation
   * কোনো API KEY ছাড়াই এটি কাজ করবে।
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
  }) => {
    if (typeof puter === 'undefined') {
      throw new Error("Puter.js লোড হয়নি। দয়া করে ইন্টারনেট কানেকশন চেক করুন।");
    }

    try {
      // মেসেজ হিস্ট্রি বা কন্টেন্টকে একটি স্ট্রিং প্রোম্পটে রূপান্তর করা
      let historyText = "";
      if (Array.isArray(params.contents)) {
        historyText = params.contents.map((msg: any) => {
          const role = msg.role === 'user' ? 'User' : 'Assistant';
          const text = msg.parts ? msg.parts[0].text : (msg.text || '');
          return `${role}: ${text}`;
        }).join('\n');
      } else {
        historyText = typeof params.contents === 'string' ? params.contents : JSON.stringify(params.contents);
      }

      const fullPrompt = `
        System Instruction: ${params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী।"}

        Context/History:
        ${historyText}

        দয়া করে উপরের তথ্যের ভিত্তিতে শুদ্ধ বাংলায় উত্তর দিন। যদি JSON চান তবে কেবল JSON ই দিন।
      `.trim();

      // Puter AI Chat Call (No API Key Required)
      const response = await puter.ai.chat(fullPrompt);

      const responseText = typeof response === 'string' ? response : (response?.message?.content || "");

      return {
        text: responseText,
        groundingMetadata: null, // Puter manages its own search internally
        mode: 'puter_global_v2'
      };

    } catch (e: any) {
      console.error("Puter AI Error:", e.message);
      throw new Error("এআই সার্ভার বর্তমানে ব্যস্ত। কিছুক্ষণ পর আবার চেষ্টা করুন।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

