  return (
    <div className="mx-6 mb-8 relative group">
      <div className="overflow-hidden bg-gradient-to-br from-indigo-600 to-indigo-800 dark:from-slate-900 dark:to-indigo-950 rounded-[2.5rem] p-7 md:p-8 shadow-2xl border border-white/10 relative">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>

        <div className="flex items-center gap-2 mb-4">
          <div className="bg-white/20 backdrop-blur-md p-2 rounded-lg text-white">
            <Newspaper className="w-4 h-4" />
          </div>
          <span className="text-[10px] font-black text-indigo-100 uppercase tracking-[0.3em]">Rajbari News (Puter AI)</span>
          <div className="ml-auto flex items-center gap-1.5 px-2 py-0.5 bg-amber-400/20 text-amber-400 rounded-full border border-amber-400/30">
            <Zap className="w-2.5 h-2.5 fill-amber-400" />
            <span className="text-[8px] font-black uppercase tracking-widest">Global Live</span>
          </div>
        </div>

        <div className="min-h-[80px] flex flex-col justify-center">
          <h3 className="text-lg md:text-xl font-black text-white leading-tight mb-4 animate-slide-up transition-all duration-500">
            {news[currentIndex]?.title}
          </h3>

          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-bold text-indigo-200 bg-white/10 px-3 py-1 rounded-full border border-white/10">
                {news[currentIndex]?.source}
              </span>
              <span className="text-[10px] font-bold text-indigo-300">
                {news[currentIndex]?.time}
              </span>
            </div>
            {news[currentIndex]?.link && (
              <a href={news[currentIndex]?.link} target="_blank" className="text-white/50 hover:text-white transition-colors">
                <ExternalLink className="w-5 h-5" />
              </a>
            )}
          </div>
        </div>

        <div className="absolute bottom-4 right-8 flex gap-2">
          <button onClick={prevSlide} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl text-white transition-all backdrop-blur-md active:scale-90">
            <ChevronLeft className="w-4 h-4" />
          </button>
          <button onClick={nextSlide} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl text-white transition-all backdrop-blur-md active:scale-90">
            <ChevronRight className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

