import { RAJBARI_DATA } from './constants.tsx';
import { GoogleGenAI } from "@google/genai";

// Declare puter for TypeScript environment
declare const puter: any;

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      // Find JSON block even if model wraps it in Markdown code blocks
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Puter.js and Google Gemini AI Call implementation
   * Always prefers Google Gemini if API_KEY is available.
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string; 
    tools?: any[];
    responseMimeType?: string;
    responseSchema?: any;
    model?: string;
  }) => {
    // API_KEY must be obtained exclusively from the environment variable process.env.API_KEY
    const apiKey = process.env.API_KEY;

    // Use Google GenAI if API key is present
    if (apiKey) {
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Normalize contents for Gemini
        let normalizedContents = params.contents;
        if (typeof params.contents === 'string') {
          normalizedContents = [{ role: 'user', parts: [{ text: params.contents }] }];
        } else if (Array.isArray(params.contents)) {
          normalizedContents = params.contents.map((msg: any) => {
            if (typeof msg === 'string') return { role: 'user', parts: [{ text: msg }] };
            // Gemini uses 'model' role, ensure compatibility if 'assistant' is used
            const role = msg.role === 'model' || msg.role === 'assistant' ? 'model' : 'user';
            const parts = msg.parts || [{ text: msg.text || '' }];
            return { role, parts };
          });
        }

        const response = await ai.models.generateContent({
          model: params.model || 'gemini-3-flash-preview',
          contents: normalizedContents,
          config: {
            systemInstruction: params.systemInstruction,
            tools: params.tools,
            responseMimeType: params.responseMimeType,
            responseSchema: params.responseSchema,
          },
        });

        // The response.text is a property, not a method.
        return {
          text: response.text || "",
          groundingMetadata: response.candidates?.[0]?.groundingMetadata || null,
          mode: 'gemini_api'
        };
      } catch (geminiError: any) {
        console.error("Gemini API Error:", geminiError);
        // Fallback continues below
      }
    }

    // Fallback to Puter.js AI Call implementation
    if (typeof puter !== 'undefined') {
      try {
        // মেসেজ হিস্ট্রি বা কন্টেন্টকে একটি স্ট্রিং প্রোম্পটে রূপান্তর করা
        let historyText = "";
        if (Array.isArray(params.contents)) {
          historyText = params.contents.map((msg: any) => {
            const role = msg.role === 'user' ? 'User' : 'Assistant';
            const text = msg.parts ? msg.parts[0].text : (msg.text || '');
            return `${role}: ${text}`;
          }).join('\n');
        } else {
          historyText = typeof params.contents === 'string' ? params.contents : JSON.stringify(params.contents);
        }

        const fullPrompt = `
          System Instruction: ${params.systemInstruction || "আপনি রাজবাড়ী জেলার একজন ডিজিটাল সহকারী।"}

          Context/History:
          ${historyText}

          দয়া করে উপরের তথ্যের ভিত্তিতে শুদ্ধ বাংলায় উত্তর দিন। যদি JSON চান তবে কেবল JSON ই দিন।
        `.trim();

        // Puter AI Chat Call (No API Key Required)
        const response = await puter.ai.chat(fullPrompt);

        const responseText = typeof response === 'string' ? response : (response?.message?.content || "");

        return {
          text: responseText,
          groundingMetadata: null, // Puter manages its own search internally
          mode: 'puter_global_v2'
        };
      } catch (puterError: any) {
        console.error("Puter AI Error:", puterError.message);
        throw new Error("এআই সার্ভার বর্তমানে ব্যস্ত। কিছুক্ষণ পর আবার চেষ্টা করুন।");
      }
    }

    throw new Error("AI service unavailable. Please check your connection or API key.");
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

