interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [lastUpdateTime, setLastUpdateTime] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[], isLive?: boolean }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    isLive: false
  });

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else if (category === 'jobs') {
        await runJobsAI();
      } else if (category === 'notices') {
        await runNoticesAI();
      } else if (category === 'holidays') {
        await runHolidaysAI();
      } else {
        const items = await db.getCategory(category);
        setData(items);
      }
    } catch (e: any) {
      const items = await db.getCategory(category);
      setData(items);
      setError("ডেটা লোড করতে সমস্যা হচ্ছে।");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  const runMarketAI = async () => {
    try {
      const response = await db.callAI({
        contents: "রাজবাড়ী জেলার বর্তমান বাজারদরের একটি JSON তালিকা দিন। ফিল্ড: name, unit, priceRange।",
        systemInstruction: "আপনি একজন বাজার বিশ্লেষক। কেবল JSON অ্যারে রিটার্ন করুন।",
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `m-${idx}` })));
    } catch (err) {
      setData([]);
    }
  };

  const runJobsAI = async () => {
    try {
      const response = await db.callAI({
        contents: "রাজবাড়ী জেলায় বর্তমানে প্রচলিত ৫টি গুরুত্বপূর্ণ সরকারি ও বেসরকারি চাকরির খবর দিন। প্রতিটি চাকরির শিরোনাম (title), প্রতিষ্ঠানের নাম (org), বেতন (salary), যোগ্যতা (eligibility), আবেদনের শেষ তারিখ (deadline) এবং অনলাইন লিংক (link) JSON ফরম্যাটে দিন।",
        systemInstruction: "আপনি রাজবাড়ী জেলা কর্মসংস্থান অফিসার। শুধুমাত্র JSON অ্যারে দিন।",
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `j-${idx}` })));
    } catch (err) {
      setData([]);
    }
  };

  const runNoticesAI = async () => {
    try {
      const response = await db.callAI({
        contents: "রাজবাড়ী জেলার বর্তমান ৫টি গুরুত্বপূর্ণ জরুরি নোটিশ বা বিজ্ঞপ্তির তালিকা দিন। ফিল্ড: title, date, summary।",
        systemInstruction: "আপনি জেলা তথ্য অফিসার। শুধুমাত্র JSON অ্যারে দিন।",
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `n-${idx}` })));
    } catch (err) {
      setData([]);
    }
  };

  const runHolidaysAI = async () => {
    try {
      const response = await db.callAI({
        contents: "২০২৪-২০২৫ সালের বাংলাদেশের ১০টি প্রধান সরকারি ছুটির তালিকা দিন। ফিল্ড: name, date, type।",
        systemInstruction: "আপনি একজন সরকারি কর্মকর্তা। শুধুমাত্র JSON অ্যারে দিন।",
      });
      const parsedData = db.extractJSON(response.text);
      if (parsedData) setData(parsedData.map((item: any, idx: number) => ({ ...item, id: `h-${idx}` })));
    } catch (err) {
      setData([]);
    }
  };

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setLastUpdateTime(new Date().toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit' }));

    setAiInference({ 
      delayMinutes: 0, 
      confidence: 0, 
      reason: 'সার্চ ইঞ্জিন থেকে ট্রেনের লাইভ আপডেট সংগ্রহ করা হচ্ছে...', 
      isAI: true, 
      sources: [],
      isLive: false 
    });

    try {
      const now = new Date().toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit', hour12: true });
      const prompt = `
      লাইভ ট্রেন ট্র্যাকিং রিকোয়েস্ট:
      ট্রেনের নাম: "${train.name}"
      রুট: [${train.detailedRoute}]
      নির্ধারিত সময়: ${train.departure}
      বর্তমান সময়: ${now}

      কাজ:
      ১. ইন্টারনেটে এই ট্রেনের গত ১ ঘণ্টার কোনো লাইভ আপডেট থাকলে তা খুঁজে বের করুন। 
      ২. যদি লাইভ কোনো তথ্য না থাকে, তবে বর্তমান সময় অনুযায়ী ট্রেনটি রুট ম্যাপের ঠিক কোন স্টেশনে থাকার কথা তা হিসেব করুন।
      ৩. উত্তরে বর্তমান স্টেশনের নাম স্পষ্টভাবে উল্লেখ করুন।
      ৪. উত্তরের শেষে অবশ্যই "[STATION: স্টেশনের নাম]" এবং "[MODE: LIVE বা SCHEDULED]" লিখুন।
      `;

      const response = await db.callAI({
        contents: prompt,
        systemInstruction: "আপনি রাজবাড়ী রেলওয়ে ট্র্যাকিং অ্যাসিস্ট্যান্ট। পুটার এআই নেটওয়ার্ক ব্যবহার করে রিয়েল-টাইম তথ্য দিন।"
      });

      const text = response.text || "";
      const stationMatch = text.match(/\[STATION:\s*(.*?)\]/i);
      const modeMatch = text.match(/\[MODE:\s*(.*?)\]/i);

      if (stationMatch && stationMatch[1]) {
        const found = stationMatch[1].trim();
        const stations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = stations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      }

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 1, 
        reason: text.replace(/\[.*?\]/g, '').trim(), 
        isAI: true, 
        sources: [],
        isLive: modeMatch?.[1]?.includes('LIVE') || false
      });
    } catch (e: any) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: "সার্ভার সংযোগ বিচ্ছিন্ন। অনুগ্রহ করে পুনরায় চেষ্টা করুন।", 
        isAI: false, 
        sources: [],
        isLive: false
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const renderItem = (item: any) => {
    if (category === 'market_price') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-emerald-50 dark:bg-emerald-950/30 flex items-center justify-center rounded-2xl text-emerald-600 shadow-inner"><DollarSign className="w-7 h-7" /></div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-lg">{item.name}</h4><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p></div>
        </div>
        <div className="text-right"><div className="text-lg font-black text-slate-800 dark:text-white">{item.priceRange}</div></div>
      </div>
    );

    if (category === 'jobs') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden relative group">
        <div className="flex items-start gap-4 mb-4">
          <div className="w-14 h-14 bg-purple-50 dark:bg-purple-900/20 flex items-center justify-center rounded-2xl text-purple-600 shrink-0"><Briefcase className="w-7 h-7" /></div>
          <div className="flex-1">
            <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-0.5">{item.title}</h4>
            <p className="text-xs font-bold text-slate-500 dark:text-slate-400">{item.org}</p>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-3 mb-5">
           <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">যোগ্যতা</p>
              <p className="text-xs font-bold text-slate-700 dark:text-slate-200">{item.eligibility}</p>
           </div>
           <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">বেতন</p>
              <p className="text-xs font-bold text-slate-700 dark:text-slate-200">{item.salary}</p>
           </div>
        </div>
        <div className="flex items-center justify-between pt-4 border-t border-slate-50 dark:border-slate-800">
           <div className="flex items-center gap-2 text-rose-500">
              <Clock className="w-3.5 h-3.5" />
              <span className="text-[10px] font-black uppercase tracking-widest">{item.deadline}</span>
           </div>
           {item.link && (
             <a href={item.link} target="_blank" className="flex items-center gap-1.5 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">
                আবেদন করুন <ExternalLink className="w-3 h-3" />
             </a>
           )}
        </div>
      </div>
    );

    if (category === 'notices') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] mb-4 border border-slate-100 dark:border-slate-800 shadow-sm">
        <div className="flex items-center gap-4 mb-3">
          <div className="w-12 h-12 bg-orange-50 dark:bg-orange-950/30 flex items-center justify-center rounded-2xl text-orange-600"><Megaphone className="w-6 h-6" /></div>
          <div className="flex-1">
            <h4 className="font-bold text-slate-800 dark:text-white text-base leading-tight">{item.title}</h4>
            <p className="text-[10px] font-black text-slate-400 uppercase mt-1">{item.date}</p>
          </div>
        </div>
        <p className="text-xs text-slate-600 dark:text-slate-400 leading-relaxed font-medium">{item.summary}</p>
      </div>
    );

    if (category === 'holidays') return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-indigo-50 dark:bg-indigo-950/30 rounded-2xl text-indigo-600"><CalendarDays className="w-6 h-6" /></div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-sm">{item.name}</h4><p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.date}</p></div>
        </div>
        <span className="bg-amber-50 dark:bg-amber-950/30 text-amber-600 text-[9px] font-black px-3 py-1.5 rounded-full border border-amber-100 dark:border-amber-900/50 uppercase tracking-widest">{item.type}</span>
      </div>
    );

    if (category === 'trains') return (
      <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 hover:border-indigo-400 transition-all group relative overflow-hidden">
        <div className="flex items-start justify-between relative z-10">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:scale-110 transition-transform"><TrainFront className="w-6 h-6" /></div>
            <div>
              <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
            </div>
          </div>
          <div className="text-right">
             <div className="bg-emerald-50 dark:bg-emerald-950/30 text-emerald-600 text-[9px] font-black px-2 py-0.5 rounded-full mb-1 border border-emerald-100">PUTER AI TRACK</div>
             <p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p>
          </div>
        </div>
      </div>
    );

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm transition-all hover:shadow-md">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl shadow-inner">{item.icon || <Info className="w-6 h-6 text-indigo-500" />}</div>
          <div><h4 className="font-bold text-slate-800 dark:text-white text-sm">{item.name || item.title || item.org}</h4><p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.mobile || item.time || item.deadline || item.number}</p></div>
        </div>
        {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 rounded-2xl active:scale-90 transition-all"><Phone className="w-5 h-5" /></a>}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-40 max-w-lg mx-auto">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-slate-800 dark:text-white uppercase leading-none mb-1">
            {category === 'trains' ? 'স্মার্ট ট্রেন ট্র্যাকিং' : 
             category === 'market_price' ? 'বাজারদর (AI)' : 
             category === 'jobs' ? 'চাকরি বিজ্ঞপ্তি' : 
             category === 'notices' ? 'জরুরি নোটিশ' : 
             category === 'holidays' ? 'ছুটির তালিকা' : 'বিস্তারিত তালিকা'}
          </h3>
          <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em]">Global Puter Network</p>
        </div>
        <button onClick={fetchData} className="bg-white dark:bg-slate-900 p-3.5 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800 text-indigo-600 active:rotate-180 transition-all">
           <RefreshCcw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-6">
          <Loader2 className="w-16 h-16 animate-spin text-indigo-600 opacity-20" />
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">ডাটাবেস চেক করা হচ্ছে...</p>
        </div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? data.map(renderItem) : (
            <div className="text-center py-20 px-10">
               <AlertCircle className="w-12 h-12 text-slate-200 mx-auto mb-4" />
               <p className="text-slate-400 font-bold text-sm">দুঃখিত, বর্তমানে কোনো তথ্য পাওয়া যায়নি। অনুগ্রহ করে রিফ্রেশ করুন।</p>
            </div>
          )}
        </div>
      )}

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex items-end md:items-center justify-center p-4">
          <div className="bg-slate-50 dark:bg-slate-900 w-full max-w-lg rounded-[3rem] overflow-hidden shadow-3xl relative animate-slide-up flex flex-col max-h-[90vh]">
            <button onClick={() => { setSelectedTrain(null); setCurrentStation(null); }} className="absolute top-6 right-6 p-2 bg-white dark:bg-slate-800 rounded-full text-slate-400 z-50 shadow-md hover:text-rose-500 transition-all"><X className="w-5 h-5" /></button>

            <div className="p-8 pb-32 overflow-y-auto no-scrollbar">
               <div className="flex items-center gap-4 mb-8">
                 <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-indigo-200">
                    <TrainFront className="w-7 h-7" />
                 </div>
                 <div>
                    <h3 className="text-xl font-black text-slate-800 dark:text-white leading-tight">{selectedTrain.name}</h3>
                    <div className="flex items-center gap-2 mt-1">
                       <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full ${aiInference.isLive ? 'bg-emerald-100 text-emerald-600 border border-emerald-200' : 'bg-amber-100 text-amber-600 border border-amber-200'}`}>
                         {aiInference.isLive ? 'Live Track' : 'Predicted Location'}
                       </span>
                       <span className="text-[8px] font-bold text-slate-400">আপডেট: {lastUpdateTime}</span>
                    </div>
                 </div>
               </div>

               <div className="bg-white dark:bg-slate-800/50 rounded-[2rem] p-6 border border-slate-100 dark:border-slate-800 shadow-sm mb-8 relative">
                  <div className="flex items-center gap-2 mb-3">
                    <Radio className={`w-4 h-4 ${isInferring ? 'animate-pulse text-indigo-500' : 'text-emerald-500'}`} />
                    <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Puter AI Control Report</span>
                  </div>

                  <p className="text-sm font-medium text-slate-700 dark:text-slate-200 leading-relaxed">
                    {aiInference.reason}
                  </p>
               </div>

               <div className="space-y-4">
                 <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                    <MapPin className="w-3 h-3" /> রুট ও বর্তমান অবস্থান
                 </h4>
                 <div className="relative pl-8 space-y-6 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[1.5px] before:bg-slate-200 dark:before:bg-slate-700">
                    {selectedTrain.detailedRoute.split(',').map((st, idx) => {
                      const stationName = st.trim();
                      const isCurrent = currentStation && (stationName.includes(currentStation) || currentStation.includes(stationName));
                      return (
                        <div key={idx} className="relative flex items-center gap-4">
                          <div className={`absolute -left-[22px] w-3.5 h-3.5 rounded-full border-2 bg-white dark:bg-slate-900 transition-all duration-700 ${isCurrent ? 'border-indigo-600 bg-indigo-600 scale-150 shadow-[0_0_15px_rgba(79,70,229,0.4)]' : 'border-slate-300 dark:border-slate-600'}`}></div>
                          <span className={`text-xs font-bold transition-all ${isCurrent ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-slate-400'}`}>{stationName}</span>
                          {isCurrent && <div className="ml-auto w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>}
                        </div>
                      );
                    })}
                 </div>
               </div>
            </div>

            <div className="absolute bottom-0 left-0 right-0 p-6 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800">
               <button 
                 disabled={isInferring}
                 onClick={() => runTrainAIInference(selectedTrain)}
                 className="w-full py-5 bg-indigo-600 rounded-[1.8rem] flex items-center justify-center gap-3 text-white font-black shadow-xl active:scale-95 transition-all disabled:opacity-50"
               >
                 {isInferring ? <Loader2 className="w-5 h-5 animate-spin" /> : <Navigation className="w-5 h-5" />}
                 {isInferring ? 'তথ্য খোঁজা হচ্ছে...' : 'লাইভ ট্র্যাকিং শুরু করুন'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoryView;

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Loader2, 
  TrainFront,
  X,
  Sparkles,
  Info,
  Navigation,
  RefreshCcw,
  DollarSign,
  AlertCircle,
  Clock,
  Search,
  ExternalLink,
  Globe,
  Radio,
  Briefcase,
  Megaphone,
  CalendarDays,
  ChevronRight,
  UserCheck,
  ShieldAlert
} from 'lucide-react';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';
import { RAJBARI_DATA } from '../constants.tsx';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [lastUpdateTime, setLastUpdateTime] = useState<string | null>(null);
  const [aiInference, setAiInference] = useState<AIInference & { sources?: any[], isLive?: boolean }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false,
    sources: [],
    isLive: false
  });

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      if (category === 'market_price') {
        await runMarketAI();
      } else if (category === 'jobs') {
        await runJobsAI();
      } else if (category === 'notices') {
        await runNoticesAI();
      } else if (category === 'holidays') {
        await runHolidaysAI();
      } else {
        const items = await db.getCategory(category);
        setData(items);
      }
    } catch (e: any) {
      const items = await db.getCategory(category);
      setData(items);
      setError("ডেটা লোড করতে সমস্যা হচ্ছে।");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  const runMarketAI = async () => {
    try {
      const response = await db.callAI({
