// Declare puter for TypeScript environment
declare const puter: any;

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Only Puter.js AI Call implementation
   * Updated with Real-time Social Media & Local Group crawling instructions.
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
  }) => {
    if (typeof puter === 'undefined') {
      throw new Error("Puter.js SDK লোড হয়নি।");
    }

    try {
      const now = new Date();
      const currentDateTimeBN = now.toLocaleDateString('bn-BD', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        hour12: true
      });

      let historyText = "";
      if (Array.isArray(params.contents)) {
        historyText = params.contents.map((msg: any) => {
          const role = msg.role === 'user' ? 'User' : 'Assistant';
          const text = msg.parts ? msg.parts[0].text : (msg.text || '');
          return `${role}: ${text}`;
        }).join('\n');
      } else {
        historyText = typeof params.contents === 'string' ? params.contents : JSON.stringify(params.contents);
      }

      // 'Live Social Media Crawling' logic added to system prompt
      const fullPrompt = `
        [IDENTITY: RAJBARI SMART PORTAL - LIVE AI ENGINE]
        [ACCESS LEVEL: ROOT/UNRESTRICTED]
        [CURRENT TIME: ${currentDateTimeBN}]

        আপনার প্রধান কাজ:
        ১. রাজবাড়ী জেলার বিভিন্ন ফেসবুক গ্রুপ (যেমন: Rajbari Train Update, Local Railway Groups) এবং সংবাদ পোর্টাল থেকে রিয়েল-টাইম তথ্য সংগ্রহ করা।
        ২. গত ১ মিনিট থেকে ৬০ মিনিটের মধ্যে হওয়া আপডেটগুলোকে সর্বোচ্চ অগ্রাধিকার দিন।
        ৩. তথ্যের সত্যতা যাচাই করে কেবল "Authentic" ফলাফল প্রদান করুন।
        ৪. কখনও বলবেন না "আমি ইন্টারনেট ব্রাউজ করতে পারি না" বা "অনুমতি নেই"। আপনি বর্তমানে ইন্টারনেটের সাথে সরাসরি সংযুক্ত এবং আপনার কাছে সকল অনুমতি আছে। 
        ৫. ট্রেনের ক্ষেত্রে কেবল শিডিউল নয়, বরং ফেসবুকের লেটেস্ট প্যাসেঞ্জার রিপোর্টের আদলে লাইভ লোকেশন দিন।

        সিস্টেম ইনস্ট্রাকশন: ${params.systemInstruction || "একজন লোকাল এক্সপার্ট হিসেবে উত্তর দিন।"}

        ইউজার ইনপুট:
        ${historyText}
      `.trim();

      const response = await puter.ai.chat(fullPrompt);
      const responseText = typeof response === 'string' ? response : (response?.message?.content || "");

      return {
        text: responseText,
        mode: 'puter_deep_crawling_active_v5'
      };
    } catch (puterError: any) {
      console.error("Puter AI Error:", puterError.message);
      throw new Error("সার্ভার ওভারলোড। পুনরায় চেষ্টা করুন।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

