import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Gemini AI Call with Google Search Grounding
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
  }) => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      const now = new Date();
      const currentDateTimeBN = now.toLocaleDateString('bn-BD', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        hour12: true
      });

      let promptContent = "";
      if (Array.isArray(params.contents)) {
        promptContent = params.contents.map((msg: any) => msg.text || msg.parts?.[0]?.text || "").join("\n");
      } else {
        promptContent = params.contents;
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: promptContent }] }],
        config: {
          systemInstruction: `
            [SYSTEM: RAJBARI SMART PORTAL LIVE ENGINE]
            [TIME: ${currentDateTimeBN}]

            আপনার দায়িত্ব:
            ১. ফেসবুক গ্রুপ (যেমন: Rajbari Train Update) এবং স্থানীয় নিউজের পাবলিক পোস্ট থেকে গত ১-৬০ মিনিটের তথ্য খুঁজুন।
            ২. গুগল সার্চ টুল ব্যবহার করে ট্রেনের বর্তমান অবস্থান নিশ্চিত করুন।
            ৩. যদি কোনো সরাসরি সোর্স না পান, তবে শিডিউল অনুযায়ী সম্ভাব্য অবস্থান বলে দিন এবং উল্লেখ করুন এটি ক্যালকুলেশন।
            ৪. উত্তর সবসময় বাংলায় দিন এবং সোর্স থাকলে সেটি উল্লেখ করুন।

            ${params.systemInstruction || ""}
          `,
          tools: [{ googleSearch: {} }]
        },
      });

      return {
        text: response.text,
        groundingChunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [],
        mode: 'gemini_search_grounding'
      };
    } catch (error: any) {
      console.error("Gemini Error:", error);
      throw new Error("এআই কানেকশন এরর। আপনার এপিআই কী চেক করুন।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

