      const match = text.match(stationRegex);
      if (match) {
        const found = match[1].trim();
        const stations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = stations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      }

      // Extract URLs from grounding metadata
      const rawSources = response.groundingChunks || [];
      const extractedLinks = rawSources
        .filter((c: any) => c.web)
        .map((c: any) => ({ title: c.web.title, uri: c.web.uri }));

      setSources(extractedLinks);

      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0.98, 
        reason: text, 
        isAI: true 
      });
    } catch (e: any) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: "সার্ভার ব্যস্ত। দয়া করে পুনরায় চেষ্টা করুন।", 
        isAI: false 
      });
    } finally { 
      setIsInferring(false); 
    }
