                 <div>
                    <h3 className="text-xl font-black text-slate-800 dark:text-white leading-tight">{selectedTrain.name}</h3>
                    <div className="flex items-center gap-2 mt-1">
                       <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-blue-100 text-blue-600 border border-blue-200 flex items-center gap-1`}>
                         <Globe className="w-2.5 h-2.5" /> রিয়েল-টাইম স্ক্যান সক্রিয়
                       </span>
                       <span className="text-[8px] font-bold text-slate-400">আপডেট: {lastUpdateTime}</span>
                    </div>
                 </div>
               </div>

               <div className="bg-white dark:bg-slate-800/50 rounded-[2.2rem] p-6 border border-slate-100 dark:border-slate-800 shadow-sm mb-8 relative">
                  <div className="flex items-center gap-2 mb-3">
                    <Radio className={`w-4 h-4 ${isInferring ? 'animate-pulse text-indigo-500' : 'text-emerald-500'}`} />
                    <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest">লাইভ স্ক্যান রিপোর্ট</span>
                  </div>

                  <div className="prose prose-sm dark:prose-invert">
                    <p className="text-sm font-medium text-slate-700 dark:text-slate-200 leading-relaxed">
                      {aiInference.reason}
                    </p>
                  </div>

                  {sources.length > 0 && (
                    <div className="mt-6 pt-6 border-t border-slate-100 dark:border-slate-800">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3">ইনফরমেশন সোর্স (Authentic Sources):</p>
                      <div className="flex flex-wrap gap-2">
                        {sources.map((s, idx) => (
                          <a key={idx} href={s.uri} target="_blank" className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-50 dark:bg-slate-800 rounded-full text-[9px] font-bold text-indigo-600 dark:text-indigo-400 border border-slate-100 dark:border-slate-700 hover:bg-indigo-50 transition-all">
                            <LinkIcon className="w-3 h-3" /> {s.title.slice(0, 20)}...
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
               </div>

               <div className="space-y-4">
                 <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                    <MapPin className="w-3 h-3" /> রুট ট্র্যাকিং ভিজ্যুয়ালাইজেশন
                 </h4>
                 <div className="relative pl-8 space-y-6 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[1.5px] before:bg-slate-200 dark:before:bg-slate-700">
                    {selectedTrain.detailedRoute.split(',').map((st, idx) => {
                      const stationName = st.trim();
                      const isCurrent = currentStation && (stationName.includes(currentStation) || currentStation.includes(stationName));
                      return (
                        <div key={idx} className="relative flex items-center gap-4">
                          <div className={`absolute -left-[22px] w-3.5 h-3.5 rounded-full border-2 bg-white dark:bg-slate-900 transition-all duration-700 ${isCurrent ? 'border-indigo-600 bg-indigo-600 scale-150 shadow-[0_0_15px_rgba(79,70,229,0.4)]' : 'border-slate-300 dark:border-slate-600'}`}></div>
                          <span className={`text-xs font-bold transition-all ${isCurrent ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-slate-400'}`}>{stationName}</span>
                          {isCurrent && <div className="ml-auto flex items-center gap-1">
                            <span className="text-[8px] font-black text-indigo-500 uppercase">এখানে আছে</span>
                            <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-ping"></div>
                          </div>}
                        </div>
                      );
                    })}
                 </div>
               </div>
            </div>

            <div className="absolute bottom-0 left-0 right-0 p-6 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800">
               <button 
                 disabled={isInferring}
                 onClick={() => runTrainAIInference(selectedTrain)}
                 className="w-full py-5 bg-indigo-600 rounded-[1.8rem] flex items-center justify-center gap-3 text-white font-black shadow-xl active:scale-95 transition-all disabled:opacity-50"
               >
                 {isInferring ? <Loader2 className="w-5 h-5 animate-spin" /> : <RefreshCcw className="w-5 h-5" />}
                 {isInferring ? 'গুগল ও ফেসবুক স্ক্যান করা হচ্ছে...' : 'লাইভ রিপোর্ট আপডেট করুন'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoryView;

