import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Loader2, 
  TrainFront,
  X,
  Sparkles,
  Info,
  Navigation,
  RefreshCcw,
  DollarSign,
  AlertCircle,
  Clock,
  Search,
  ExternalLink,
  Globe,
  Radio,
  Briefcase,
  Megaphone,
  CalendarDays,
  ChevronRight,
  UserCheck,
  ShieldAlert,
  Facebook,
  Link as LinkIcon,
  Activity
} from 'lucide-react';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';
import { RAJBARI_DATA } from '../constants.tsx';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [lastUpdateTime, setLastUpdateTime] = useState<string | null>(null);
  const [sources, setSources] = useState<any[]>([]);
  const [aiInference, setAiInference] = useState<AIInference & { reason: string, isAI: boolean }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: false
  });

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      const items = await db.getCategory(category);
      setData(items);
    } catch (e: any) {
      setError("নেটওয়ার্ক চেক করুন।");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  const runTrainAIInference = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setSources([]);
    setLastUpdateTime(new Date().toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit' }));

    setAiInference({ 
      delayMinutes: 0, 
      confidence: 0, 
      reason: 'রেলওয়ে লাইভ সার্ভার এবং সোশ্যাল মিডিয়া স্ক্যান করা হচ্ছে...', 
      isAI: true 
    });

    let apiData = null;
    try {
      // Step 1: Fetch from Live Backend provided by user
      const apiResponse = await fetch(`https://live-train-tracking-backend.onrender.com/train/location/?id=${train.id}`);
      if (apiResponse.ok) {
        apiData = await apiResponse.json();
      }
    } catch (e) {
      console.warn("API Fetch failed, falling back to AI Search Grounding.");
    }

    try {
      // Step 2: Use Gemini to interpret API data or perform Search Grounding
      const prompt = `
      [REAL-TIME TRAIN TRACKING COMMAND]
      ট্রেন: "${train.name}" (ID: ${train.id})
      রুট: ${train.route}

      লাইভ এপিআই ডেটা: ${apiData ? JSON.stringify(apiData) : "ডেটা পাওয়া যায়নি, গুগল সার্চ ব্যবহার করুন"}

      আপনার কাজ:
      ১. যদি এপিআই ডেটা থাকে, তবে সেটি বাংলায় ব্যাখ্যা করুন। 
      ২. যদি এপিআই ডেটা না থাকে, তবে গুগল সার্চ গ্রাউন্ডিং ব্যবহার করে ফেসবুক (Rajbari Train Update) এবং ওয়েব থেকে গত ১ ঘণ্টার আপডেট খুঁজে বের করুন।
      ৩. ট্রেনের বর্তমান লোকেশন (Station) এবং বর্তমান স্ট্যাটাস (Running/Delayed) পরিষ্কার করে বলুন।
      `;

      const response = await db.callAI({
        contents: prompt,
        systemInstruction: "আপনি রাজবাড়ী লাইভ ট্র্যাকার। এপিআই এবং সোশ্যাল মিডিয়া ডেটার সমন্বয়ে সবচেয়ে সঠিক লাইভ লোকেশন রিপোর্ট দিন।"
      });

      const text = response.text || "";

      // Extract Station for the route visualization
      const stationMatch = text.match(/(অবস্থান|বর্তমানে|স্টেশন)[:\-\s]+([^\n\.,]+)/i);
      if (stationMatch) {
        const found = stationMatch[2].trim();
        const stations = train.detailedRoute.split(',').map(s => s.trim());
        const bestMatch = stations.find(s => found.includes(s) || s.includes(found));
        setCurrentStation(bestMatch || found);
      }

      setSources(response.groundingChunks || []);
      setAiInference({ 
        delayMinutes: 0, 
        confidence: apiData ? 1.0 : 0.9, 
        reason: text, 
        isAI: true 
      });
    } catch (e: any) {
      setAiInference({ 
        delayMinutes: 0, 
        confidence: 0, 
        reason: "সার্ভার ব্যস্ত। পুনরায় চেষ্টা করুন।", 
        isAI: false 
      });
    } finally { 
      setIsInferring(false); 
    }
  };

  const renderItem = (item: any) => {
    if (category === 'trains') return (
      <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainAIInference(item); }} className="bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 transition-all group relative overflow-hidden">
        <div className="flex items-start justify-between relative z-10">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:scale-110 transition-transform"><TrainFront className="w-6 h-6" /></div>
            <div>
              <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
            </div>
          </div>
          <div className="text-right">
             <div className="bg-indigo-50 dark:bg-indigo-950/30 text-indigo-600 text-[9px] font-black px-2 py-0.5 rounded-full mb-1 border border-indigo-100 uppercase flex items-center gap-1">
               <Activity className="w-2 h-2" /> Live API + AI
             </div>
             <p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p>
          </div>
        </div>
      </div>
    );

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm transition-all hover:shadow-md">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl shadow-inner">
            {item.icon || <Info className="w-6 h-6 text-indigo-500" />}
          </div>
          <div>
            <h4 className="font-bold text-slate-800 dark:text-white text-sm">{item.name || item.title || item.org}</h4>
            <p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.number || item.mobile || item.time || item.deadline}</p>
          </div>
        </div>
        {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 rounded-2xl active:scale-90 transition-all"><Phone className="w-5 h-5" /></a>}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-40 max-w-lg mx-auto">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-slate-800 dark:text-white uppercase leading-none mb-1">
            {category === 'trains' ? 'স্মার্ট রেলওয়ে পোর্টাল' : 'বিস্তারিত তালিকা'}
          </h3>
          <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em]">Real-time API Link-up</p>
        </div>
        <button onClick={fetchData} className="bg-white dark:bg-slate-900 p-3.5 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800 text-indigo-600 active:rotate-180 transition-all">
           <RefreshCcw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-6">
          <Loader2 className="w-16 h-16 animate-spin text-indigo-600 opacity-20" />
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">ডাটাবেস চেক করা হচ্ছে...</p>
        </div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? data.map(renderItem) : <div className="text-center py-20 px-10"><p className="text-slate-400 font-bold text-sm">তথ্য লোড হচ্ছে...</p></div>}
        </div>
      )}

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex items-end md:items-center justify-center p-4">
          <div className="bg-slate-50 dark:bg-slate-900 w-full max-w-lg rounded-[3rem] overflow-hidden shadow-3xl relative animate-slide-up flex flex-col max-h-[95vh]">
            <button onClick={() => { setSelectedTrain(null); setCurrentStation(null); }} className="absolute top-6 right-6 p-2 bg-white dark:bg-slate-800 rounded-full text-slate-400 z-50 shadow-md hover:text-rose-500 transition-all"><X className="w-5 h-5" /></button>

            <div className="p-8 pb-32 overflow-y-auto no-scrollbar">
               <div className="flex items-center gap-4 mb-8">
                 <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl">
                    <TrainFront className="w-7 h-7" />
                 </div>
                 <div>
                    <h3 className="text-xl font-black text-slate-800 dark:text-white leading-tight">{selectedTrain.name}</h3>
                    <div className="flex items-center gap-2 mt-1">
                       <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-600 border border-emerald-200 flex items-center gap-1`}>
                         <Globe className="w-2.5 h-2.5" /> API Connection: Active
                       </span>
                       <span className="text-[8px] font-bold text-slate-400">আপডেট: {lastUpdateTime}</span>
                    </div>
                 </div>
               </div>

               <div className="bg-white dark:bg-slate-800/50 rounded-[2.2rem] p-6 border border-slate-100 dark:border-slate-800 shadow-sm mb-8 relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-4 opacity-5">
