import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Gemini AI Call to Explain Data
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
  }) => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      let promptContent = "";
      if (Array.isArray(params.contents)) {
        promptContent = params.contents.map((msg: any) => msg.text || msg.parts?.[0]?.text || "").join("\n");
      } else {
        promptContent = params.contents;
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: promptContent }] }],
        config: {
          systemInstruction: `
            আপনি রাজবাড়ী স্মার্ট পোর্টালের একজন সহায়ক। 
            আপনার কাজ হলো দেওয়া টেকনিক্যাল ডেটা (JSON) বিশ্লেষণ করে সহজ বাংলায় ব্যবহারকারীকে বুঝিয়ে বলা।
            কোনো অপ্রাসঙ্গিক কথা বলবেন না। ট্রেনটি কোথায় আছে, কত বেগে চলছে এবং সম্ভাব্য স্ট্যাটাস কী - তা সুন্দর করে গুছিয়ে বলুন।
            ${params.systemInstruction || ""}
          `,
          temperature: 0.2,
        },
      });

      return {
        text: response.text,
        mode: 'smart_explainer'
      };
    } catch (error: any) {
      console.error("AI Error:", error);
      throw new Error("এআই কানেকশন এরর।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

