            যদি লাইভ এপিআই ডেটা না পাওয়া যায়, তবে আপনি ট্রেনের শিডিউল (Schedule) দেখে সম্ভাব্য অবস্থান বলবেন।
            আপনার ভাষা হবে সাবলীল, বন্ধুত্বপূর্ণ এবং তথ্যবহুল।
            অপ্রাসঙ্গিক কথা এড়িয়ে সরাসরি পয়েন্টে উত্তর দেবেন।
            ${params.systemInstruction || ""}
          `,
          temperature: 0.3,
        },
      });

      return {
        text: response.text,
        mode: 'puter_smart_explainer'
      };
    } catch (error: any) {
      console.error("AI Error:", error);
      throw new Error("এআই বর্তমানে সাড়া দিচ্ছে না।");
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

