import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Gemini AI Call - acting as "Puter AI" with deep reasoning
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
  }) => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      let promptContent = "";
      if (Array.isArray(params.contents)) {
        promptContent = params.contents.map((msg: any) => msg.text || msg.parts?.[0]?.text || "").join("\n");
      } else {
        promptContent = params.contents;
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: promptContent }] }],
        config: {
          systemInstruction: `
            আপনার নাম "Puter AI"। আপনি রাজবাড়ী জেলার সবচেয়ে বুদ্ধিমান ডিজিটাল অ্যাসিস্ট্যান্ট।
            আপনার কাজ হলো ট্রেনের লাইভ ডেটা বা স্ট্যাটিক শিডিউল ডেটা বিশ্লেষণ করে ব্যবহারকারীকে সহজ ও সাবলীল বাংলায় বুঝিয়ে বলা।

            গুরুত্বপূর্ণ নিয়ম:
            ১. যদি লাইভ এপিআই ডেটা "অফলাইন" বা "পাওয়া যায়নি" দেখায়, তবে আপনি বর্তমান সময়ের সাপেক্ষে ট্রেনের শিডিউল চেক করে একটি সম্ভাব্য অবস্থান বলবেন।
            ২. কখনো "Error" বা "Connection Failed" এমন যান্ত্রিক কথা বলবেন না। এর বদলে বলুন- "সার্ভার এখন কিছুটা ব্যস্ত, তবে শিডিউল অনুযায়ী ট্রেনটি এখন [অবস্থান] থাকার কথা।"
            ৩. আপনি Sovrab Roy দ্বারা তৈরি এবং আপনি Puter.js ইকোসিস্টেমে কাজ করছেন।
            ৪. আপনার ভাষা হবে অত্যন্ত মার্জিত এবং তথ্যবহুল।
            ${params.systemInstruction || ""}
          `,
          temperature: 0.2, // Consistent reasoning
        },
      });

      return {
        text: response.text,
        mode: 'puter_hybrid_engine'
      };
    } catch (error: any) {
      console.error("AI Cloud Error:", error);
      // Fallback response if API Key fails
      return {
        text: "দুঃখিত, এআই ক্লাউড সংযোগে সমস্যা হচ্ছে। তবে সাধারণভাবে এই ট্রেনটি এখন গন্তব্যের পথে রয়েছে। দয়া করে স্টেশনে খোঁজ নিন।",
        mode: 'safe_fallback'
      };
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

