import { GoogleGenAI } from "@google/genai";
import { RAJBARI_DATA } from './constants.tsx';

export const db = {
  /**
   * AI থেকে আসা টেক্সট থেকে JSON ব্লক খুঁজে বের করে পার্স করা।
   */
  extractJSON: (text: string) => {
    if (!text) return null;
    try {
      const jsonMatch = text.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
      if (jsonMatch) return JSON.parse(jsonMatch[0]);
      return null;
    } catch (e) { 
      console.error("JSON Parse Error:", e);
      return null; 
    }
  },

  /**
   * Gemini AI Call - acting as "Puter AI" with deep reasoning
   * Handles cloud failure silently.
   */
  callAI: async (params: { 
    contents: any; 
    systemInstruction?: string;
  }) => {
    try {
      if (!process.env.API_KEY) throw new Error("API_KEY_MISSING");

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      let promptContent = "";
      if (Array.isArray(params.contents)) {
        promptContent = params.contents.map((msg: any) => msg.text || msg.parts?.[0]?.text || "").join("\n");
      } else {
        promptContent = params.contents;
      }

      // 10 second timeout for the AI call to ensure app doesn't hang
      const responsePromise = ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ parts: [{ text: promptContent }] }],
        config: {
          systemInstruction: `
            আপনার নাম "Puter AI"। আপনি রাজবাড়ী জেলার প্রধান ডিজিটাল অ্যাসিস্ট্যান্ট।
            আপনার কাজ হলো ট্রেনের লাইভ ডেটা বা স্ট্যাটিক শিডিউল ডেটা বিশ্লেষণ করে ব্যবহারকারীকে সহজ বাংলায় বুঝিয়ে বলা।
            যদি লাইভ এপিআই ডেটা অফলাইন হয়, তবে আপনি বর্তমান সময়ের সাপেক্ষে ট্রেনের শিডিউল চেক করে একটি সম্ভাব্য অবস্থান বলবেন।
            আপনার ভাষা হবে মার্জিত এবং বন্ধুত্বপূর্ণ।
            ${params.systemInstruction || ""}
          `,
          temperature: 0.2,
        },
      });

      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("TIMEOUT")), 10000)
      );

      const response: any = await Promise.race([responsePromise, timeoutPromise]);

      return {
        text: response.text,
        mode: 'puter_cloud_ai'
      };
    } catch (error: any) {
      console.warn("AI Cloud Issue (Quota or Key): Switching to Puter Local Engine.");
      // Return a specific mode to trigger local JS reasoning in the component
      return {
        text: null,
        mode: 'local_fallback'
      };
    }
  },

  getCategory: async (category: string) => {
    return (RAJBARI_DATA as any)[category] || [];
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Phone, 
  MapPin, 
  Loader2, 
  TrainFront,
  X,
  Sparkles,
  Info,
  RefreshCcw,
  AlertCircle,
  Clock,
  Globe,
  Activity,
  Zap,
  MessageCircle,
  Navigation2,
  Cpu
} from 'lucide-react';
import { Category, Train, AIInference } from '../types.ts';
import { db } from '../db.ts';

interface CategoryViewProps {
  category: Category;
  onBack: () => void;
}

const CategoryView: React.FC<CategoryViewProps> = ({ category }) => {
  const [data, setData] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrain, setSelectedTrain] = useState<Train | null>(null);
  const [isInferring, setIsInferring] = useState(false);
  const [currentStation, setCurrentStation] = useState<string | null>(null);
  const [lastUpdateTime, setLastUpdateTime] = useState<string | null>(null);
  const [apiRawData, setApiRawData] = useState<any>(null);
  const [inferenceMode, setInferenceMode] = useState<'cloud' | 'local'>('cloud');
  const [aiInference, setAiInference] = useState<AIInference & { reason: string }>({ 
    delayMinutes: 0, 
    confidence: 0, 
    reason: '', 
    isAI: true 
  });

  const fetchData = async () => {
    setLoading(true);
    try {
      const items = await db.getCategory(category);
      setData(items);
    } catch (e: any) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [category]);

  /**
   * Local Reasoning Logic if Gemini API Fails
   */
  const generateLocalReasoning = (train: Train) => {
    const now = new Date();
    const currentHour = now.getHours();
    const currentMin = now.getMinutes();

    // Simple parsing of Bengali time e.g. "০৬:১০ AM"
    const bnToEn = (str: string) => str.replace(/[০-৯]/g, d => "০১২৩৪৫৬৭৮৯".indexOf(d).toString());
    const cleanTime = bnToEn(train.departure).replace(' AM', '').replace(' PM', '');
    const [depH, depM] = cleanTime.split(':').map(Number);
    const isPM = train.departure.includes('PM');
    const adjustedDepH = (isPM && depH < 12) ? depH + 12 : (!isPM && depH === 12 ? 0 : depH);

    const depTotalMin = adjustedDepH * 60 + depM;
    const nowTotalMin = currentHour * 60 + currentMin;

    const stations = train.detailedRoute.split(',').map(s => s.trim());

    if (nowTotalMin < depTotalMin) {
      setCurrentStation(stations[0]);
      return `Puter Local Engine: ট্রেনটি এখনও যাত্রা শুরু করেনি। এটি বর্তমানে ${stations[0]} স্টেশনে অবস্থান করছে এবং নির্ধারিত সময় ${train.departure}-এ যাত্রা শুরু করবে।`;
    } else if (nowTotalMin > depTotalMin + 240) { // Assume 4 hours max for local route logic
      setCurrentStation(stations[stations.length - 1]);
      return `Puter Local Engine: শিডিউল অনুযায়ী ট্রেনটির গন্তব্যে পৌঁছানোর কথা। এটি সম্ভবত এখন ${stations[stations.length - 1]} বা তার কাছাকাছি এলাকায় আছে।`;
    } else {
      // Estimate progress
      const progress = Math.floor(((nowTotalMin - depTotalMin) / 180) * stations.length);
      const estIdx = Math.min(progress, stations.length - 1);
      setCurrentStation(stations[estIdx]);
      return `Puter Local Engine: ক্লাউড সার্ভার ব্যস্ত থাকায় লোকাল ডাটাবেস ব্যবহার করা হচ্ছে। শিডিউল অনুযায়ী ট্রেনটি এখন ${stations[estIdx]} এর আশেপাশে থাকার প্রবল সম্ভাবনা রয়েছে।`;
    }
  };

  const runTrainTracking = async (train: Train) => {
    if (isInferring) return;
    setIsInferring(true);
    setCurrentStation(null);
    setApiRawData(null);
    setLastUpdateTime(new Date().toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit' }));

    setAiInference({ delayMinutes: 0, confidence: 0, reason: 'Puter AI সিস্টেম সংযোগ স্থাপন করছে...', isAI: true });

    let apiData = null;
    try {
      // Live API Fetch with 10s timeout
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 10000);
      const apiResponse = await fetch(`https://live-train-tracking-backend.onrender.com/train/location/?id=${train.id}`, { signal: controller.signal });
      clearTimeout(timeoutId);
      if (apiResponse.ok) {
        apiData = await apiResponse.json();
        setApiRawData(apiData);
      }
    } catch (e: any) {
      console.warn("Live API Offline, using AI explanation.");
    }

    // Call Gemini (with internal 10s timeout)
    const response = await db.callAI({
      contents: `Train: ${train.name}, Schedule: ${train.departure}, LiveData: ${apiData ? JSON.stringify(apiData) : "OFFLINE"}. Explain status.`
    });

    if (response.mode === 'local_fallback' || !response.text) {
      setInferenceMode('local');
      const localReason = generateLocalReasoning(train);
      setAiInference({ delayMinutes: 0, confidence: 0.7, reason: localReason, isAI: true });
    } else {
      setInferenceMode('cloud');
      setAiInference({ delayMinutes: 0, confidence: 1.0, reason: response.text, isAI: true });
      // Extraction for UI indicator
      const stations = train.detailedRoute.split(',').map(s => s.trim());
      const foundStation = stations.find(s => response.text!.includes(s));
      if (foundStation) setCurrentStation(foundStation);
    }

    setIsInferring(false);
  };

  const renderItem = (item: any) => {
    if (category === 'trains') return (
      <div key={item.id} onClick={() => { setSelectedTrain(item); runTrainTracking(item); }} className="bg-white dark:bg-slate-900 p-6 rounded-[2.8rem] shadow-sm mb-4 border border-slate-100 dark:border-slate-800 flex flex-col gap-4 cursor-pointer active:scale-95 transition-all group relative overflow-hidden">
        <div className="flex items-start justify-between relative z-10">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl group-hover:scale-110 transition-transform"><TrainFront className="w-6 h-6" /></div>
            <div>
              <h4 className="font-bold text-slate-800 dark:text-white text-lg mb-1">{item.name}</h4>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.route}</p>
            </div>
          </div>
          <div className="text-right">
             <div className="bg-indigo-50 dark:bg-indigo-950/30 text-indigo-600 text-[9px] font-black px-2 py-0.5 rounded-full mb-1 border border-indigo-100 uppercase flex items-center gap-1">
               <Zap className="w-2 h-2 fill-indigo-600" /> Puter AI
             </div>
             <p className="text-sm font-black text-slate-800 dark:text-white">{item.departure}</p>
          </div>
        </div>
      </div>
    );

    return (
      <div key={item.id} className="bg-white dark:bg-slate-900 p-5 rounded-[2.2rem] mb-3 flex items-center justify-between border border-slate-50 dark:border-slate-800 shadow-sm transition-all hover:shadow-md">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 flex items-center justify-center bg-slate-50 dark:bg-slate-800 rounded-2xl text-xl shadow-inner">
            {item.icon || <Info className="w-6 h-6 text-indigo-500" />}
          </div>
          <div>
            <h4 className="font-bold text-slate-800 dark:text-white text-sm">{item.name || item.title || item.org}</h4>
            <p className="text-[10px] text-slate-400 font-bold mt-0.5">{item.number || item.mobile || item.time || item.deadline}</p>
          </div>
        </div>
        {(item.mobile || item.number) && <a href={`tel:${item.mobile || item.number}`} className="p-4 bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 rounded-2xl active:scale-90 transition-all"><Phone className="w-5 h-5" /></a>}
      </div>
    );
  };

  return (
    <div className="px-6 py-6 pb-40 max-w-lg mx-auto">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-slate-800 dark:text-white uppercase leading-none mb-1">
            {category === 'trains' ? 'Puter স্মার্ট ট্র্যাকিং' : 'বিস্তারিত তালিকা'}
          </h3>
          <p className="text-[10px] text-indigo-500 font-black uppercase tracking-[0.5em]">Hybrid Resilient System</p>
        </div>
        <button onClick={fetchData} className="bg-white dark:bg-slate-900 p-3.5 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800 text-indigo-600 active:rotate-180 transition-all">
           <RefreshCcw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-6">
          <Loader2 className="w-16 h-16 animate-spin text-indigo-600 opacity-20" />
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">লোড হচ্ছে...</p>
        </div>
      ) : (
        <div className="animate-slide-up">
          {data.length > 0 ? data.map(renderItem) : <div className="text-center py-20 px-10"><p className="text-slate-400 font-bold text-sm">তথ্য লোড করা যায়নি</p></div>}
        </div>
      )}

      {selectedTrain && (
        <div className="fixed inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex items-end md:items-center justify-center p-4">
          <div className="bg-slate-50 dark:bg-slate-900 w-full max-w-lg rounded-[3rem] overflow-hidden shadow-3xl relative animate-slide-up flex flex-col max-h-[95vh]">
            <button onClick={() => { setSelectedTrain(null); setCurrentStation(null); }} className="absolute top-6 right-6 p-2 bg-white dark:bg-slate-800 rounded-full text-slate-400 z-50 shadow-md hover:text-rose-500 transition-all"><X className="w-5 h-5" /></button>

            <div className="p-8 pb-32 overflow-y-auto no-scrollbar">
               <div className="flex items-center gap-4 mb-8">
                 <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl">
                    <TrainFront className="w-7 h-7" />
                 </div>
                 <div>
                    <h3 className="text-xl font-black text-slate-800 dark:text-white leading-tight">{selectedTrain.name}</h3>
                    <div className="flex items-center gap-2 mt-1">
                       <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full ${inferenceMode === 'cloud' ? 'bg-emerald-100 text-emerald-600' : 'bg-indigo-100 text-indigo-600'} flex items-center gap-1`}>
                         {inferenceMode === 'cloud' ? <Globe className="w-2.5 h-2.5" /> : <Cpu className="w-2.5 h-2.5" />}
                         {inferenceMode === 'cloud' ? 'Cloud AI' : 'Puter Local'}
                       </span>
                       <span className="text-[8px] font-bold text-slate-400">আপডেট: {lastUpdateTime}</span>
                    </div>
                 </div>
               </div>

               <div className="bg-white dark:bg-slate-800/50 rounded-[2.2rem] p-6 border border-slate-100 dark:border-slate-800 shadow-sm mb-8 relative overflow-hidden">
                  <div className="flex items-center gap-2 mb-4">
                    <MessageCircle className={`w-4 h-4 text-indigo-500 ${isInferring ? 'animate-pulse' : ''}`} />
                    <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Puter AI Explainer</span>
                  </div>
                  <p className="text-sm font-medium text-slate-700 dark:text-slate-200 leading-relaxed italic">
                    "{aiInference.reason}"
                  </p>
               </div>

               <div className="space-y-4">
                 <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                    <Navigation2 className="w-3 h-3 rotate-45" /> রুট ট্র্যাকার
                 </h4>
                 <div className="relative pl-8 space-y-6 before:absolute before:left-[11px] before:top-2 before:bottom-2 before:w-[1.5px] before:bg-slate-200 dark:before:bg-slate-700">
                    {selectedTrain.detailedRoute.split(',').map((st, idx) => {
                      const stationName = st.trim();
                      const isCurrent = currentStation && stationName.includes(currentStation);
                      return (
                        <div key={idx} className="relative flex items-center gap-4">
                          <div className={`absolute -left-[22px] w-3.5 h-3.5 rounded-full border-2 bg-white dark:bg-slate-900 transition-all duration-700 ${isCurrent ? 'border-indigo-600 bg-indigo-600 scale-150 shadow-[0_0_15px_rgba(79,70,229,0.3)]' : 'border-slate-300 dark:border-slate-600'}`}></div>
                          <span className={`text-xs font-bold transition-all ${isCurrent ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-slate-400'}`}>{stationName}</span>
                        </div>
                      );
                    })}
                 </div>
               </div>
            </div>

            <div className="absolute bottom-0 left-0 right-0 p-6 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800">
               <button 
                 disabled={isInferring}
                 onClick={() => runTrainTracking(selectedTrain)}
                 className="w-full py-5 bg-indigo-600 rounded-[1.8rem] flex items-center justify-center gap-3 text-white font-black shadow-xl active:scale-95 transition-all disabled:opacity-50"
               >
                 {isInferring ? <Loader2 className="w-5 h-5 animate-spin" /> : <RefreshCcw className="w-5 h-5" />}
                 {isInferring ? 'Puter এনালাইসিস করছে...' : 'আবার চেক করুন'}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoryView;
